// Normalize both Apollo and manual inputs to common schema
const input = $input.first().json;
let leads = [];

if (input.people && Array.isArray(input.people)) {
  // Apollo or manual source
  leads = input.people.map((p, idx) => ({
    lead_id: `lead_${Date.now()}_${idx}`,
    first_name: p.first_name || '',
    last_name: p.last_name || '',
    email: p.email || null,
    email_confidence: p.email_confidence || 0,
    company_name: p.company_name || '',
    job_title: p.job_title || '',
    industry: p.industry || '',
    website_domain: p.website_domain || '',
    website: `https://${p.website_domain}` || '',
    linkedin_url: p.person_linkedin_url || '',
    instagram_handle: p.instagram_handle || '',
    source: p.source || 'unknown',
    phone: p.phone || null
  }));
}

return { leads };

// Enrich leads with Hunter.io if email is missing or low confidence
const { leads } = $input.first().json;
const hunterApiKey = process.env.HUNTER_API_KEY;

if (!hunterApiKey || !leads || !Array.isArray(leads)) {
  return { leads };
}

// Leads without email need enrichment
const leadsToEnrich = leads.filter(l => !l.email || l.email_confidence < 70);
const enrichedLeads = [];

for (const lead of leads) {
  if (lead.email && lead.email_confidence >= 70) {
    enrichedLeads.push(lead);
  } else {
    // Mark for enrichment - actual Hunter call happens in next HTTP node
    enrichedLeads.push({ ...lead, needs_enrichment: true });
  }
}

return { leads: enrichedLeads };

// Filter & Qualify leads - swimwear specific
const { leads } = $input.first().json;

const qualified = leads.map(lead => {
  const hasEmail = !!lead.email && lead.email_confidence >= 70;
  const hasName = !!(lead.first_name || lead.company_name);
  const hasContext = !!(lead.company_name || lead.industry);

  const nicheMatch = !lead.industry ? true : 
    ['swim', 'bikini', 'resort', 'surf', 'beach', 'apparel', 'fashion'].some(
      kw => (lead.industry || '').toLowerCase().includes(kw)
    );

  let disqualify_reason = null;
  let is_qualified = false;

  if (!hasEmail) {
    disqualify_reason = 'no_verified_email';
  } else if (!hasName) {
    disqualify_reason = 'missing_name';
  } else if (!hasContext) {
    disqualify_reason = 'missing_company_context';
  } else if (!nicheMatch) {
    disqualify_reason = 'niche_mismatch';
  } else {
    is_qualified = true;
  }

  return {
    ...lead,
    qualified: is_qualified,
    disqualify_reason,
    sourced_at: new Date().toISOString()
  };
});

return { leads: qualified };

// Dedup check: compare new leads against existing Leads tab
const { leads } = $input.first().json;
const existingLeads = $('Read: Leads Tab (for dedup)').first().json;

const existingEmails = (existingLeads || []).map(row => row.Email?.toLowerCase()).filter(Boolean);
const existingCompanies = (existingLeads || []).map(row => row.Company?.toLowerCase()).filter(Boolean);

const dedupedLeads = leads.map(lead => {
  const isDupEmail = existingEmails.includes(lead.email?.toLowerCase());
  const isDupCompany = existingCompanies.includes(lead.company_name?.toLowerCase());
  const isDuplicate = isDupEmail || isDupCompany;

  return {
    ...lead,
    is_duplicate: isDuplicate,
    skip: isDuplicate ? true : false
  };
});

return { leads: dedupedLeads };
